-- ============================================================
-- IMAGO — locales/deDE/data/snippets.lua
-- ============================================================

if GetLocale() ~= "deDE" then return end

IMAGO.LoreSnippets["FUN_FACT"] = {
    { text = "Geistheiler sind in Wahrheit abtrünnige Val'kyr." },
    { text = [[Nat Pagle sagte einst: „Man kann sie nicht alle an den Haken bekommen, wenn man nicht auswirft."]] },
    { text = "IMAGO – Die Chronik der Unvergessenen wird nie vollendet – nur erweitert." },
    { text = "Murlocs sprechen Nerglish." },
    { text = "Die Defiasbruderschaft hatte recht." },
    { text = "Bolvar Fordragon war länger der Lichkönig als Arthas Menethil." },
    { text = "Das Flüstern im Thronsaal von Lordaeron ist das letzte Gespräch zwischen Arthas und seinem Vater aus Warcraft III. Dreh deine Umgebungslaustärke auf, um es selbst zu hören!" },
    { text = "Kleintiere wie Robben und Eber sind bekanntermaßen explodiert, wenn man sie wiederholt angestupst hat. Dieses Phänomen hat seit dem Ende des Dritten Krieges auf mysteriöse Weise aufgehört." },
    { text = "Illidan Sturmgrimm führt die Kriegsgleven von Azzinoth. In ihrer ursprünglichen Darstellung hatten sie Pandagesichter in den Griff graviert." },
    { text = "Viele prominente Charaktere sind dafür bekannt, Tabak zu rauchen, darunter König Terenas, Khadgar, Uther Lichtbringer und Tirion Fordring." },
    { text = "Stratholme hat ein Schild, das den Weg ins Schlingendorntal weist, obwohl diese Region auf der anderen Seite des Kontinents liegt." },
    { text = "Schreckensrosse werden vom Stallmeister-Dämonenlord Hel'nurath auf dem Planeten Xoroth gezüchtet. Zu seinem Entsetzen stehlen Hexenmeister sie immer wieder für ihre Beschwörungsrituale." },
    { text = "Alleria und Turalyon sind nicht verheiratet, obwohl sie seit über tausend Jahren zusammen sind." },
    { text = "Goblinschredder zeigen auf ihrem Hauptbildschirm ein Bild von Kerrigan aus StarCraft: Brood War." },
    { text = "Thrall hat blaue Augen, was unter Orcs ein äußerst seltenes Merkmal ist." },
    { text = "Lordaeron wurde nach Lordain benannt, einem menschlichen General, der vor fast 3.000 Jahren eine entscheidende Rolle in den Trollkriegen spielte." },
    { text = "Oger veranstalten regelmäßig Armdrück-Meisterschaften. Wächter Mol'dar ist seit sechs Jahren in Folge der Armdrück-Champion von Düsterbruch." },
    { text = "Trolle benennen ihre Städte häufig nach ihrem Stamm. Die Gurubashi erbauten Zul'Gurub, die Amani leben in Zul'Aman, die Farraki suchen Schutz in Zul'Farrak und die Drakkari besitzen Zul'Drak." },
    { text = "Wenn es um alkoholische Getränke geht, empfiehlt Tirion Fordring den \"Herdweiler Ambrosia\"." },
    { text = "Die Kirin Tor besitzen ein Kompendium voller Regeln und Vorschriften zur Anwendung der Verwandlungszauber. Es umfasst Hunderte von Seiten." },
    { text = "Drachen glauben, dass sterbliche Völker große, kunstvolle Schulterpanzer tragen, um die majestätischen Flügel der Drachen nachzuahmen." },
    { text = "Die meisten Uhren in Azeroth sind kaputt und ihre Zeiger bewegen sich nicht. Deshalb zeigen sie keine korrekte Uhrzeit an." },
    { text = "Der Gnom Tigule erfand Speiseeis und wurde unglaublich reich, indem er seine berühmte Erdbeersorte verkaufte." },
    { text = "Würgetang wurde während der Kriegsvorbereitungen für Ahn'Qiraj zur Herstellung von Eiscreme verwendet, um Soldaten gegen die Hitze der Wüste zu helfen." },
    { text = "Die Verlassenen entwickelten die Gossensprache, damit andere Völker ihre Pläne nicht belauschen konnten. Sie ist eine abgewandelte Form der Gemeinsprache, die Elemente des Zwergischen und Thalassischen enthält." },
    { text = "Der Hexenmeisterzauber \"Auge von Kilrogg\" wurde nach Kilrogg Totauge benannt, dem früheren Orchäuptling des Clans des blutenden Auges." },
    { text = "Das Dunkle Portal besitzt auf beiden Seiten jeweils zwei humanoide Statuen. Niemand weiß, wen sie darstellen sollen." },
    { text = "\"Tauren\" ist ein Anagramm des englischen Worts \"Nature\" - Natur." },
    { text = "Die Höhlen des Wehklagens erhielten ihren Namen durch das Wassergeräusch, das durch Erdspalten strömt und dabei wie unheimliche, klagende Schreie klingt." },
    { text = "Das Schiff in den Todesminen ist ein Oger-Kampfpott, ein Schiffstyp, der während des Zweiten Krieges häufig zu sehen war." },
    { text = "Kreaturen, die unter dem Effekt von \"Fluch der Sprachen\" stehen, sind gezwungen, in Dämonisch zu sprechen." },
    { text = "\"Binärbräu\", erhältlich über den \"Bier des Monats\"-Club, verleiht vorübergehend die Fähigkeit, in Binärcode zu sprechen." },
    { text = "Der orcische Ausdruck \"Zug-zug\" bedeutet Zustimmung oder Bestätigung." },
    { text = "Gegner erscheinen niedrigerstufig, wenn man betrunken ist." },
    { text = "Verlassene können durch das Licht geheilt werden, allerdings verursacht dies starke Schmerzen." },
    { text = "Orgrimmar wurde nach Orgrim Schicksalshammer benannt, dem zweiten Kriegshäuptling der Horde." },
    { text = "Durotar wurde nach Thralls Vater Durotan vom Frostwolfklan benannt." },
    { text = "Saronit, ein Metall aus Nordend, ist das verdichtete Blut des Alten Gottes Yogg-Saron. Längerer Kontakt führt zu Wahnsinn." },
    { text = "Der 30. September ist der \"Tag der Peons\", an dem die Bewohner von Sturmwind und Orgrimmar die fleißige Arbeit der einfachen Arbeiter und Bauern der Welt feiern." },
    { text = "Obwohl er Plattenrüstung trägt und ein Schwert führt, gilt Anduin Wrynn als Priester und nicht als Paladin." },
    { text = "Beutebucht hieß ursprünglich \"Schwarzwasserbucht\"." },
    { text = "Abenteurer mussten sich ein dauerhaftes drakonisches Mal in die Haut brennen lassen, um Zugang zum Pechschwingenhort zu erhalten. Dieses Brandmal wurde jedoch niemals sichtbar auf den Spielermodellen dargestellt." },
    { text = "Uralte Taurenschamanen hielten die Erdelementarprinzessin Therazane einst fälschlicherweise für die Erdenmutter." },
    { text = "Nachdem Magni Bronzebart in der Altstadt von Eisenschmiede zu Diamant verwandelt wurde, war er zu schwer, um die Aufzüge von Donnerfels zu benutzen." },
    { text = "Chen Sturmbräu nennt die Dunkelspeertrolle, die in Donnerfels leben, \"blaue Tauren\"." },
    { text = "Fein gemahlene Draenei-Rute ist eine wirkungsvolle Zutat für nekromantische Experimente." },
    { text = "Leerenelfen empfinden die musikalischen Geräusche der Naaru als äußerst störend." },
}

IMAGO.LoreSnippets["DID_YOU_KNOW"] = {
    { text = "Azeroth kann sich auf fünf verschiedene Dinge beziehen: Azeroth den Titanen, Azeroth den Planeten, Azeroth den Kontinent (Östliche Königreiche), Azeroth die Region (südlich von Khaz Modan) und Azeroth das Königreich (heute Königreich Sturmwind)." },
    { text = "Goblins sind ein fehlgeschlagenes Experiment des Titanenhüters Mimiron." },
    { text = "Der Dämmerwald war einst als Hellerwald bekannt, bis zum Tod des Wächters Medivh. Sein Tod löste eine Welle von Teufelsenergie aus, die eine ewige Nacht verursachte." },
    { text = "Elfen sind magisch weiterentwickelte Trolle." },
    { text = "Die Leere ist nicht leer, sondern eine Verschmelzung von Energien, ähnlich dem brennenden Inneren eines Sterns. Viele wurden von ihr in den Wahnsinn getrieben." },
    { text = "Die Getriebenen sind Blutelfen, die ihrer Magiesucht erlegen sind und dadurch verwildert und deformiert wurden." },
    { text = "Oger sind überraschend gute Schiffsbauer und Seeleute." },
    { text = "Tartek der Wütende war eine der mächtigsten Monstrositäten, die je erschaffen wurden. Wir wissen von seiner Existenz nur durch eine einzige Schriftrolle der Geißel in der Schwarzen Festung." },
    { text = "Die Wildhammerzwerge sind berühmt dafür, auf Greifen zu reiten und Sturmhämmer zu führen - verzauberte Waffen, die beim Werfen mit der Kraft von Donner und Blitz zuschlagen." },
    { text = "Die Scheiben von Norgannon, manchmal auch als Platinscheiben bezeichnet, sind ein wundersames Artefakt, das in Uldaman verborgen liegt. Sie enthalten eine Bibliothek der gesamten Geschichte Azeroths, und neue Informationen werden weiterhin in ihnen aufgezeichnet, sobald sie geschehen." },
    { text = "Obsidian besitzt möglicherweise die Fähigkeit, Mana zu manipulieren - wie der Obsidianwächter in Uldaman sowie die von der Geißel und den Qiraji eingesetzten Obsidianzerstörer zeigen." },
    { text = "Obwohl die Streitkräfte des Scharlachroten Klosters hauptsächlich aus Menschen bestehen, befinden sich in der Scharlachroten Waffenkammer drei Statuen zu Ehren nichtmenschlicher Mitglieder des Scharlachroten Kreuzzugs." },
    { text = "In extrem seltenen Fällen erschafft das Heilige Licht mit einer Wiederbelebung einen Untoten, der durch das Licht statt durch Nekromantie animiert wird." },
    { text = "Dämonen können nur im Wirbelnden Nether dauerhaft getötet werden, und Naaru können nur im Reich des Lichts endgültig sterben. Nur außergewöhnlich mächtige Wesen können diese Einschränkung umgehen." },
    { text = "Kobolde hängen so sehr an ihren Kerzen, weil sie eine urtümliche Angst vor dem Leerengespenst namens \"Die Finsternis\" haben." },
    { text = "Mitglieder der Horde können gnomische Ingenieurskunst lernen – dank des Gnoms Glotz Widrikus. Er wurde fälschlicherweise für Verbrechen beschuldigt, die er nie begangen hat, und aus Gnomeregan verbannt. Aus Rache bringt er nun der Horde sein Wissen bei." },
    { text = "Azeroth hat zwei Monde: die Weiße Dame und das Blaue Kind. Alle 430 Jahre überlagern sie sich in einem Ereignis namens die Umarmung, weil es so aussieht, als würde die \"Mutter\" ihr \"Kind\" halten." },
    { text = "Es ist reiner Zufall, dass der orcische Schwarzfelsklan sein Hauptquartier im Schwarzfels hat. Der Klan wurde bereits lange vor der Invasion Azeroths nach dem Schwarzfelserz auf Draenor benannt." },
    { text = "Einst existierte ein legendäres Schwert namens Andonisus, der Seelenschlächter. Es konnte während des Kampfes gegen den Dämon Atiesh in Stratholme nur bis zu fünf Minuten lang geführt werden. Wenn sein Träger nicht geheilt wurde, tötete die Waffe ihn innerhalb von 20 Sekunden." },
    { text = "Der Anführer des Scharlachroten Kreuzzugs war in Wahrheit ein als Mensch getarnter Dämon." },
    { text = "Obwohl sie Verbündete waren, griffen die Ritter der Schwarzen Klinge die Kapelle des hoffnungsvollen Lichts an, um Tirion Fordrings Leichnam als Mitglied der Vier Reiter wiederzuerwecken. Ihr Vorhaben scheiterte jedoch." },
    { text = "Zu den Standardrationen von Eisenschmiede gehören Beuschelwurst und Bier. Das ist seit über tausend Jahren ein Grundbestandteil der zwergischen Armeeversorgung." },
    { text = "Die Allianz stellte Thrall einst im Steinkrallengebirge eine Falle, indem sich ihre Soldaten in Schafe verwandelten, um ihn aus dem Hinterhalt anzugreifen. Thrall durchschaute den Trick jedoch sofort, da Schafe nicht in Kalimdor heimisch sind." },
    { text = "Unter Nachtelfen gibt es seit langer Zeit den Glauben, dass jene mit goldenen Augen zu Großem bestimmt sind. Zu den berühmtesten Nachtelfen mit goldenen Augen gehören Königin Azshara und Illidan Sturmgrimm." },
    { text = "Die orcische Tradition des Mak'gora ist ein ritueller Kampf auf Leben und Tod, mit dem Streitigkeiten beigelegt werden - meist im Kampf um die Führung." },
    { text = "Orcs sind von Natur aus braunhäutig. Nachdem sie das verdorbene Blut des Grubenlords Mannoroth getrunken hatten, färbte sich die Haut der meisten Orcs grün." },
    { text = "Die Straße zwischen dem Dunklen Portal und der Höllenfeuerzitadelle ist mit den Knochen tausender ermordeter Draenei gepflastert." },
    { text = "Wenn man im Thronsaal am Eingang zur Unterstadt genau hinhört, kann man im geisterhaften Flüstern hören, wie Arthas seinen Vater tötet." },
    { text = "Taurenhufe wurden als geheime Zutat für Süßigkeiten verwendet." },
    { text = "Schurken blendeten ihre Gegner früher mit einem Reizmittel aus Blassblatt. Später hörten sie damit auf und verwendeten stattdessen gewöhnlichen Schmutz oder Sand." },
    { text = "Die Dunklen Reiter des Gebirgspasses der Totenwinde waren einst eine Gruppe reisender Händler, die versuchten, Medivh gefälschte Artefakte zu verkaufen. Nun sind sie dazu verdammt, für alle Ewigkeit nach echten Artefakten zu suchen und sie dem Wächter zurückzubringen." },
    { text = "Silber ist schwer, aber schön und wird für Schmuck und Ziergegenstände verwendet. Echtsilber hingegen ist leichter und stärker als Stahl und eignet sich daher besser für Rüstungen und Waffen." },
    { text = "Die Schanksause der Kirin Tor war ein Ereignis, bei dem Magier Portale zwischen verschiedenen Bars und Tavernen der Welt erschufen. Die Teilnehmer wurden dazu ermutigt, an jedem Zielort etwas Neues zu probieren." },
    { text = "Im Wald von Elwynn kann man beobachten, wie Wölfe Kaninchen jagen und töten." },
    { text = "Es gab bisher sieben Kriegshäuptlinge der Horde: Schwarzfaust der Zerstörer, Orgrim Schicksalshammer, Ner'zhul, Thrall, Garrosh Höllschrei, Vol'jin und Sylvanas Windläufer. Heute wird die Horde von einem Rat aus Anführern regiert." },
    { text = "Der Sonnenbrunnen besaß einst eine menschliche Manifestation namens Anveena Teague." },
    { text = "Es gibt mindestens sechs abgewandelte Drachenschwärme, die korrumpierte oder experimentelle Abspaltungen der fünf Hauptschwärme darstellen." },
}

IMAGO.LoreSnippets["HISTORICAL_FACT"] = {
    { text = "Die gefürchtete C'thraxxi-Kreatur namens Kith'ix war vor Jahrtausenden ein General der Alten Götter. Er wurde besiegt und in Zul'Aman begraben, wo sein Körper bis heute ruht." },
    { text = "Dath'remar Sonnenwanderer gründete Quel'Thalas nach dem Krieg der Ahnen. Seine Statue befindet sich auf der Insel der Sonnenwanderer." },
    { text = "Der Strahlende Gesang wurde nicht nur auf Azeroth gehört, sondern auch auf der weit entfernten Welt K'aresh, kurz bevor diese zerstört wurde." },
    { text = "Die Todesschneise wurde durch den Sonnenbrunnen fast vollständig geheilt. Heutzutage sind in Silbermond nur noch wenige Spuren von Arthas' Invasion sichtbar." },
    { text = "Die Defiasbruderschaft wurde ursprünglich gegründet, nachdem das Königreich Sturmwind sich weigerte, die Steinmetze für ihre Arbeit am Wiederaufbau von Sturmwind zu bezahlen." },
    { text = "Der Sonnenbrunnen ist etwa 7.000 Jahre alt." },
    { text = "Die Stadt Sturmwind wurde etwa 1.200 Jahre vor dem Ersten Krieg gegründet. Zur Zeit von Midnight ist die Stadt physisch uralt, aber ein Großteil ihrer sichtbaren Infrastruktur wurde in den letzten 30–40 Jahren der In-Universe-Geschichte neu aufgebaut." },
    { text = "Halduron Wolkenglanz ist der erste Waldläufergeneral von Silbermond seit mindestens drei Generationen, der kein Windläufer ist." },
    { text = "Der Orc Broxigar benutzte eine verzauberte Holzaxt, um in das Bein von Sargeras zu schneiden. Er ist einer der wenigen Sterblichen, von denen bekannt ist, dass sie den Titanen verletzt haben." },
    { text = "Tanaris war einst ein üppiger Dschungel, bis die Große Teilung die Welt zerschmetterte und das Klima dauerhaft veränderte." },
    { text = "Die ersten Paladine wurden im Zweiten Krieg erschaffen, um der Schwarzen Magie der Horde entgegenzuwirken. Es war ein Sammelsurium aus Priestern mit Militärausbildung und Rittern, die heilige Schriften studieren mussten – doch die verzweifelte Maßnahme zeigte Wirkung." },
    { text = "75 Jahre vor dem Ersten Krieg wurde das Königreich Sturmwind beinahe von Gnolle vernichtet." },
    { text = "Die dornigen Ranken, aus denen der Kral der Klingenhauer und die Hügel von Razorfen bestehen, sind die sterblichen Überreste von Agamaggan, der Schweinegott. Er fiel im Kampf gegen die Brennende Legion während des Krieges der Ahnen." },
    { text = "Gnome fehlten im Dritten Krieg, weil Gnomregan zu diesem Zeitpunkt von Troggs belagert wurde." },
    { text = "Menschen entdeckten die heiligen Kräfte des Lichts vor etwa 3.000 Jahren während der Trollkriege. Mereldar war die erste menschliche Priesterin, die seine heilende Kraft herbeirief." },
    { text = "Vor etwa 250 Jahren versuchte der Schwarzeisen-Zauberthan Thaurissan, Ragnaros den Feuerfürsten zu beschwören, um seine Feinde zu vernichten. Die daraus folgende Verwüstung tötete ihn und erschuf den Schwarzfels." },
    { text = "Zweiköpfige Oger entstanden im Zweiten Krieg, als Gul'dan alte elfische Runensteine in Bauwerke umwandelte, die als Sturmaltar bekannt sind." },
    { text = "Im Zweiten Krieg verlor König Perenolde von Alterac den Glauben und wechselte die Seiten, um sich mit der Horde zu verbünden. Die Allianz zerstörte Alterac als Vergeltung für diesen Verrat." },
    { text = "Das Mondfest feiert das Ende des Krieges der Ahnen, bei dem die Völker Azeroths die Invasion der Brennenden Legion vor zehntausend Jahren zurückschlugen." },
    { text = "Im Zweiten Krieg nahm der Ork Nekros Schädelbrecher Alexstrasza gefangen und zwang ihre Kinder, für die Horde zu kämpfen." },
    { text = "Das antike Draenor war von einem Schwarmbewusstsein aus Pflanzen und Pilzen bedeckt, dem sogenannten Ewigem Wachstum. Es wurde vernichtet, als uralte Arakkoa eine Superwaffe aktivierten, die Sonnenenergie mit verheerender Wirkung einsetzte." },
    { text = "Vor etwa 2.600 Jahren wurde der erste Wächter von Trisfal erschaffen. Diese Magier wurden mit immenser Macht und der Verantwortung ausgestattet, Azeroth vor der Dämoneninvasion zu schützen." },
    { text = "Nach dem Ersten Krieg wurde das Ereignis als so bedeutsam eingestuft, dass der Kalender neu gezählt wurde. Jahr 0 markiert den Zeitpunkt, an dem die Horde zum ersten Mal in Azeroth einmarschierte." },
    { text = "Es gibt eine \"einzig wahre Zeitlinie\", und der Bronzene Drachenschwarm widmet sich ihrer Bewahrung." },
}
